import{c as n,Q as o,j as t,m as i}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"How do I configure non-production billing?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/configure-non-prod-billing.md","filePath":"guide/recipes/admin/configure-non-prod-billing.md","lastUpdated":1779094756000}'),a={name:"guide/recipes/admin/configure-non-prod-billing.md"};function r(l,e,s,d,c,u){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="how-do-i-configure-non-production-billing" tabindex="-1">How do I configure non-production billing? <a class="header-anchor" href="#how-do-i-configure-non-production-billing" aria-label="Permalink to &quot;How do I configure non-production billing?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> or <strong>Finance Admin</strong></p></div><p>Non-production environments (staging, development, sandbox, UAT, QA) are billed separately from production. You can charge for them per-tenant, by usage, or not at all — and override the policy for individual tenants.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Finance → Finance Customers</strong> and click the customer.</li><li>Switch to the <strong>Billing Setup</strong> tab and scroll to <strong>Non-Production Billing</strong>.</li><li>Pick a billing mode: <ul><li><strong>Not billed</strong> — non-prod tenants are free.</li><li><strong>Flat rate per tenant</strong> — fixed amount per non-prod tenant per cycle.</li><li><strong>Based on usage</strong> — bill non-prod meters at a discounted rate.</li></ul></li><li>Set <strong>Environment Defaults</strong> — which envs are included (typically staging + UAT), at what rate.</li><li>In the <strong>Non-Production Tenants</strong> table below, override individual tenants if needed. Manual overrides show an asterisk.</li><li>Click <strong>Save</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The next invoice itemises non-prod usage separately from prod. Tenants with manual overrides are flagged so finance can audit them. Switching modes affects only future cycles.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./configure-customer-billing">How do I configure billing for a customer?</a></li><li><a href="./create-custom-plan">How do I create a custom plan?</a></li></ul>',9)])])}const h=n(a,[["render",r]]);export{p as __pageData,h as default};
